import React from 'react';

/**
 * 用于扣出一个桥形，本来想用于画 date-range，但是最终效果不好，所以先提交在这里但是不使用
 * https://bytedance.feishu.cn/docx/doxcn9kqBZVTrbolR9ilVUzsR1X
 */
export const HoleMask: React.FC<React.SVGProps<SVGSVGElement>> = ({ style, ...props }) => (
  <svg
    height="100%"
    width="200%"
    xmlns="http://www.w3.org/2000/svg"
    style={{
      position: 'absolute',
      fill: 'currentColor',
      ...style,
    }}
    {...props}
  >
    <defs>
      <mask id="hole">
        <rect width="100%" height="100%" fill="#fff" />
        <circle cx="50%" cy="50%" r="50%" fill="#000" />
      </mask>
    </defs>
    <rect width="100%" height="100%" mask="url(#hole)" />
  </svg>
);
